#include <iostream>
#include <sstream>

class Timer {
private:
    int hours;
    int minutes;
    int seconds;

public:
    Timer(int h, int m, int s) {
        seconds = s % 60;
        int carryMinutes = s / 60;
        if (seconds < 0) {
            seconds += 60;
            carryMinutes--;
        }

        minutes = (m + carryMinutes) % 60;
        int carryHours = (m + carryMinutes) / 60;
        if (minutes < 0) {
            minutes += 60;
            carryHours--;
        }

        hours = (h + carryHours) % 24;
        if (hours < 0) {
            hours += 24;
        }
    }

    void displayTime() const {
        if (hours < 10) {
            std::cout << "0";
        }
        std::cout << hours << ":";

        if (minutes < 10) {
            std::cout << "0";
        }
        std::cout << minutes << ":";

        if (seconds < 10) {
            std::cout << "0";
        }
        std::cout << seconds << std::endl;
    }
};

int main() {
    std::stringstream ss;
    std::streambuf* oldCout = std::cout.rdbuf();
    std::cout.rdbuf(ss.rdbuf());

    Timer t1(10, 30, 45);
    t1.displayTime();

    Timer t2(2, 5, 8);
    t2.displayTime();

    Timer t3(23, 59, 59);
    t3.displayTime();

    Timer t4(0, 0, 0);
    t4.displayTime();

    Timer t5(25, 65, 70);
    t5.displayTime();

    Timer t6(-1, -1, -1);
    t6.displayTime();

    std::cout.rdbuf(oldCout);
    std::cout << ss.str();

    return 0;
}
